insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (33, 30000, 13, 2, 20003, 20, 0, '', '', 0, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (34, 30000, 14, 8, 91002, 100, 0, '', '', 0, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (35, 30000, 15, 2, 24001, 1, 0, '', '', 0, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (36, 40000, 1, 8, 91002, 100, 0, '', '', 0, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (37, 40001, 1, 8, 91002, 150, 107501, 'ぺコリーヌ', '今日は記念日、お祝いですね！\\n焼肉、お寿司、ピザ、ケーキ～☆\\nあなたとパーティできるなんて、\\n幸せです～♪', 1, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (38, 40001, 2, 8, 91002, 150, 107601, 'コッコロ', 'この記念日を迎えられたのは、\\n主さまの器量の賜物\\nさすがは主さまでございます\\nえらい、えらい♪', 1, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (39, 40001, 3, 8, 91002, 150, 107801, 'キャル', 'あんたもけっこうやるじゃない！\\nちょっとは…割と…け、けっこう\\n見直しちゃったわ\\n褒めてあげる♪', 1, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (40, 40001, 4, 8, 91002, 150, 107701, 'スズメ', 'あなたと私にとって、\\n今日は特別な日\\nあなたの支えがあるから、\\n私は頑張れるんです！', 1, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (41, 40001, 5, 8, 91002, 150, 107901, 'タマキ', '今日はキミにとっての\\n特別な記念日だにゃ\\nキミの活躍にはいつも\\n猫ながら感謝してるにゃ～♪', 1, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (42, 40001, 6, 8, 91002, 150, 107501, 'ぺコリーヌ', 'う～かき氷食べ過ぎて、\\n身体が冷えちゃいました…\\nあなたの体温で温めてください！\\nギューーッ♪', 2, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (43, 40001, 7, 8, 91002, 150, 107601, 'コッコロ', '夏は危険がいっぱいと申します…\\nですが、わたくしが主さまを\\nしっかりとお守りいたしますよ', 2, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (44, 40001, 8, 8, 91002, 150, 107801, 'キャル', 'ん～なんであんたと、ひと夏を\\n過ごすことになったのかな…\\n結構楽しいからいいけど！\\nさ、まだまだ遊ぶわよ！', 2, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (45, 40001, 9, 8, 91002, 150, 107701, 'スズメ', 'あなたと過ごすはじめての夏…\\nいまからドキドキが止まりません\\n楽しくて素敵な思い出が、\\nまた一つ増えるんですね♪', 2, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (46, 40001, 10, 8, 91002, 150, 107901, 'タマキ', '夏は一番の稼ぎ時にゃのに、\\n今年はキミと過ごしたいって\\n思ってるにゃ楽しい思い出\\n増やしてくれるかにゃ？', 2, 0);
insert into v1_3c23ee5a7882d233b7ce489c43dcd540425c2f237d612651cac7ee092a6ff6bd values (57, 40003, 1, 8, 91002, 150, 0, '', '', 0, 0);
